Here's a complete example:

**XAML (ItemsPage.xaml)**
```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <CollectionView.RefreshCommand>
            <Binding Path="RefreshCommand" />
        </CollectionView.RefreshCommand>

        <!-- Wrap in a RefreshView for pull-to-refresh -->
    </CollectionView>
</ContentPage>
```

Actually, `CollectionView` doesn't directly support pull-to-refresh — you wrap it in a **`RefreshView`**:

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView Command="{Binding RefreshCommand}"
                 IsRefreshing="{Binding IsRefreshing}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem, Mode=TwoWay}">

            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <VerticalStackLayout Padding="10">
                        <Label Text="{Binding Name}" FontSize="18" />
                        <Label Text="{Binding Description}" TextColor="Gray" />
                    </VerticalStackLayout>
                </DataTemplate>
            </CollectionView.ItemTemplate>

        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel (ItemsViewModel.cs)**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private bool _isRefreshing;

    private Item? _selectedItem;
    public Item? SelectedItem
    {
        get => _selectedItem;
        set
        {
            if (SetProperty(ref _selectedItem, value) && value is not null)
            {
                // Navigate, then clear selection so the same item can be re-selected
                _nav.NavigateToDetail(value);
                SelectedItem = null;
            }
        }
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items = new ObservableCollection<Item>(data);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }
}
```

**Key bindings explained:**

| Binding | Direction | Purpose |
|---|---|---|
| `ItemsSource → Items` | One-way | Drives the list from `ObservableCollection` |
| `SelectedItem` | **TwoWay** | VM receives the tap, triggers navigation, then resets to `null` |
| `IsRefreshing` | TwoWay | `RefreshView` sets it `true` on pull; VM sets it `false` when done |
| `Command → RefreshCommand` | One-way | `[RelayCommand]` generates this from `RefreshAsync` |

**Three things that trip people up:**
1. **`RefreshView` wraps `CollectionView`** — the refresh properties live on `RefreshView`, not `CollectionView`.
2. **Reset `SelectedItem` to `null`** after navigating — otherwise tapping the same item again won't fire.
3. **Set `IsRefreshing = false`** in a `finally` block — if you forget, the spinner never stops.
